'use client';
import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { createClient } from '@/lib/supabaseClient';
export default function Onboarding(){const supabase=createClient();const router=useRouter();const [form,setForm]=useState({full_name:'',age:'',height_cm:'',initial_weight_kg:'',goal:'emagrecer',level:'iniciante',training_frequency:'3',dietary_restrictions:'',health_notes:''});const [error,setError]=useState('');async function save(){const {data:{user}}=await supabase.auth.getUser();if(!user)return router.push('/auth/login');const payload={user_id:user.id,full_name:form.full_name,age:+form.age,height_cm:+form.height_cm,initial_weight_kg:+form.initial_weight_kg,current_weight_kg:+form.initial_weight_kg,goal:form.goal,level:form.level,training_frequency:+form.training_frequency,dietary_restrictions:form.dietary_restrictions,health_notes:form.health_notes,onboarding_completed:true};const {error}=await supabase.from('profiles').upsert(payload,{onConflict:'user_id'});if(error)setError(error.message);else router.push('/dashboard')}return <main className="mx-auto max-w-3xl px-4 py-10"><div className="card"><span className="badge">Primeiro acesso</span><h1 className="mt-3 text-3xl font-black">Monte seu ponto de partida</h1><div className="mt-6 grid gap-3 md:grid-cols-2"><input className="input" placeholder="Nome" onChange={e=>setForm({...form,full_name:e.target.value})}/><input className="input" placeholder="Idade" type="number" onChange={e=>setForm({...form,age:e.target.value})}/><input className="input" placeholder="Altura em cm" type="number" onChange={e=>setForm({...form,height_cm:e.target.value})}/><input className="input" placeholder="Peso inicial" type="number" onChange={e=>setForm({...form,initial_weight_kg:e.target.value})}/><select className="input" onChange={e=>setForm({...form,goal:e.target.value})}><option value="emagrecer">Emagrecer</option><option value="ganhar_massa">Ganhar massa</option><option value="condicionamento">Condicionamento</option><option value="vida_saudavel">Vida saudável</option></select><select className="input" onChange={e=>setForm({...form,level:e.target.value})}><option value="iniciante">Iniciante</option><option value="intermediario">Intermediário</option><option value="avancado">Avançado</option></select><input className="input" placeholder="Treinos por semana" type="number" onChange={e=>setForm({...form,training_frequency:e.target.value})}/><input className="input" placeholder="Restrições alimentares" onChange={e=>setForm({...form,dietary_restrictions:e.target.value})}/><textarea className="input md:col-span-2" placeholder="Observações de saúde" onChange={e=>setForm({...form,health_notes:e.target.value})}/></div><button className="btn mt-6" onClick={save}>Salvar e começar</button>{error&&<p className="mt-3 text-red-600">{error}</p>}</div></main>}
